message.content:
@startuml
!theme plain

title LIGHT's Class Diagram

package "android" {
  package "view" {
    class "View" {
      <<interface>>
      "C" + "OnClickListener"
    }
  }
  package "widget" {
    class "CompoundButton" {
      <<interface>>
      "C" + "OnCheckedChangeListener"
    }
  }
}

package "androidx" {
  package "appcompat" {
    package "app" {
      class "AppCompatActivity" {
        <<interface>>
        "C" + "AppCompatActivity"
      }
    }
  }
}

package "com" {
  package "example" {
    package "light" {
      class "BuildConfig" {
        <<interface>>
        "C" + "BuildConfig"
      }
      class "MainActivity" {
        <<interface>>
        "C" + "MainActivity"
      }
    }
  }
}

"MainActivity" ..> "AppCompatActivity" : extends
"MainActivity" ..> "OnClickListener" : implements
"MainActivity" ..> "OnCheckedChangeListener" : implements

@enduml
